-- Engagement analytics: survey_periods + survey_metrics aggregate fact table
-- and a seeded set of historical periods so the results tabs are populated for
-- demo/interpretation. Real 15Five exports replace/extend these via import.
-- Idempotent: CREATE TABLE IF NOT EXISTS + deterministic UUIDs + ON CONFLICT.
CREATE TABLE IF NOT EXISTS "survey_periods" (
  "id" uuid PRIMARY KEY DEFAULT gen_random_uuid() NOT NULL,
  "label" varchar(80) NOT NULL,
  "period_date" date NOT NULL,
  "eligible_count" integer DEFAULT 0 NOT NULL,
  "response_count" integer DEFAULT 0 NOT NULL,
  "source" varchar(16) DEFAULT 'import' NOT NULL,
  "is_current" boolean DEFAULT false NOT NULL,
  "created_at" timestamp with time zone DEFAULT now() NOT NULL
);
--> statement-breakpoint
CREATE TABLE IF NOT EXISTS "survey_metrics" (
  "id" uuid PRIMARY KEY DEFAULT gen_random_uuid() NOT NULL,
  "period_id" uuid NOT NULL REFERENCES "survey_periods"("id") ON DELETE cascade,
  "scope" varchar(16) NOT NULL,
  "department" varchar(120),
  "dimension" varchar(16) NOT NULL,
  "metric_key" varchar(64),
  "mean" numeric(4,2),
  "favorable_pct" numeric(5,2),
  "unfavorable_pct" numeric(5,2),
  "response_count" integer DEFAULT 0 NOT NULL,
  "eligible_count" integer
);
